const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');

const invoices = new Map([
  [
    'inv_1',
    {
      id: 'inv_1',
      number: 'INV-0001',
      status: 'SENT',
      currency: 'USD',
      total: 12500,
      createdAt: new Date('2026-01-10T10:00:00.000Z').toISOString(),
      dueAt: new Date('2026-02-10T10:00:00.000Z').toISOString(),
      customer: { name: 'Acme Inc', email: 'billing@acme.example' },
      lineItems: [
        { description: 'Design work', quantity: 10, unitPrice: 1000, amount: 10000 },
        { description: 'Consulting', quantity: 5, unitPrice: 500, amount: 2500 }
      ]
    }
  ],
  [
    'inv_2',
    {
      id: 'inv_2',
      number: 'INV-0002',
      status: 'PAID',
      currency: 'USD',
      total: 3000,
      createdAt: new Date('2026-02-01T10:00:00.000Z').toISOString(),
      dueAt: new Date('2026-03-01T10:00:00.000Z').toISOString(),
      customer: { name: 'Globex Corp', email: 'ap@globex.example' },
      lineItems: [{ description: 'Maintenance', quantity: 1, unitPrice: 3000, amount: 3000 }]
    }
  ]
]);

const typeDefs = `#graphql
  type Query {
    invoice(id: ID!): Invoice
  }

  type Invoice {
    id: ID!
    number: String!
    status: InvoiceStatus!
    currency: String!
    total: Int!
    createdAt: String!
    dueAt: String
    customer: Customer!
    lineItems: [LineItem!]!
  }

  enum InvoiceStatus {
    DRAFT
    SENT
    PAID
    VOID
    OVERDUE
  }

  type Customer {
    name: String!
    email: String!
  }

  type LineItem {
    description: String!
    quantity: Int!
    unitPrice: Int!
    amount: Int!
  }
`;

const resolvers = {
  Query: {
    invoice: async (_parent, { id }, context) => {
      if (!context?.user) throw new Error('UNAUTHENTICATED');
      const invoice = invoices.get(String(id));
      return invoice || null;
    }
  }
};

const server = new ApolloServer({ typeDefs, resolvers });

async function main() {
  const { url } = await startStandaloneServer(server, {
    listen: { port: process.env.PORT ? Number(process.env.PORT) : 4000 },
    context: async ({ req }) => {
      return { user: req.user || { id: 'user_1' } };
    }
  });
  console.log(`GraphQL ready at ${url}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});